function candidate(rootPrefix, resourceReference, mapLocation) {
  const reference = resourceReference == null ? "" : String(resourceReference);
  let combined;

  if (rootPrefix == null || rootPrefix === "") {
    combined = reference;
  } else {
    const prefix = String(rootPrefix);
    combined = prefix + (prefix.endsWith("/") || reference.startsWith("/") || reference === "" ? "" : "/") + reference;
  }

  const normalizePath = (input) => {
    const absolute = input.startsWith("/");
    const trailing = input.length > 1 && input.endsWith("/");
    const out = [];
    for (const part of input.split("/")) {
      if (part === "" || part === ".") continue;
      if (part === "..") {
        if (out.length && out[out.length - 1] !== "..") out.pop();
        else if (!absolute) out.push(part);
      } else {
        out.push(part);
      }
    }
    let result = (absolute ? "/" : "") + out.join("/");
    if (result === "" && absolute) result = "/";
    if (trailing && result !== "/") result += "/";
    return result;
  };

  const isUrlLike = (value) => /^[A-Za-z][A-Za-z0-9+.-]*:/.test(value) || value.startsWith("//");

  if (mapLocation != null && mapLocation !== "") {
    const map = String(mapLocation);
    if (isUrlLike(map)) {
      let base;
      try {
        const parsed = map.startsWith("//") ? new URL("http:" + map) : new URL(map);
        parsed.hash = "";
        parsed.search = "";
        parsed.pathname = parsed.pathname.replace(/[^/]*$/, "");
        base = parsed;
      } catch (error) {
        throw new Error("Invalid map location");
      }
      try {
        const resolved = new URL(combined, base);
        return (map.startsWith("//") && resolved.protocol === "http:" ? "" : resolved.protocol) + "//" + resolved.host + normalizePath(resolved.pathname) + resolved.search + resolved.hash;
      } catch (error) {
        throw new Error("Invalid resolved reference");
      }
    }

    const directory = map.replace(/[^/]*$/, "");
    combined = combined.startsWith("/") || isUrlLike(combined) ? combined : directory + combined;
  }

  if (isUrlLike(combined)) {
    try {
      const parsed = combined.startsWith("//") ? new URL("http:" + combined) : new URL(combined);
      const prefix = combined.startsWith("//") && parsed.protocol === "http:" ? "" : parsed.protocol;
      return prefix + "//" + parsed.host + normalizePath(parsed.pathname) + parsed.search + parsed.hash;
    } catch (error) {
      throw new Error("Invalid reference");
    }
  }

  return normalizePath(combined);
}
